import { useQueryClient } from '@tanstack/react-query';
import { useEffect, useRef } from 'react';
import { createInteractionState } from '@/tools/video-editor/lib/interaction-state';
import { useGallerySelection } from '@/shared/contexts/GallerySelectionContext';
import { useProjectSelectionContext } from '@/shared/contexts/ProjectContext';
import { useVideoEditorRuntime } from '@/tools/video-editor/contexts/DataProviderContext';
import { ROW_HEIGHT, TIMELINE_START_LEFT } from '@/tools/video-editor/lib/coordinate-utils';
import { useAssetManagement } from '@/tools/video-editor/hooks/useAssetManagement';
import { useAssetOperations } from '@/tools/video-editor/hooks/useAssetOperations';
import { useClipEditing } from '@/tools/video-editor/hooks/useClipEditing';
import { useClipResize } from '@/tools/video-editor/hooks/useClipResize';
import { useDerivedTimeline } from '@/tools/video-editor/hooks/useDerivedTimeline';
import { useDragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import { useEditorPreferences } from '@/tools/video-editor/hooks/useEditorPreferences';
import { useExternalDrop } from '@/tools/video-editor/hooks/useExternalDrop';
import { useTimelinePlayback } from '@/tools/video-editor/hooks/useTimelinePlayback';
import { useRenderState } from '@/tools/video-editor/hooks/useRenderState';
import { useTimelineHistory } from '@/tools/video-editor/hooks/useTimelineHistory';
import { useTimelineQueries } from '@/tools/video-editor/hooks/useTimelineQueries';
import { useTimelineSave } from '@/tools/video-editor/hooks/useTimelineSave';
import { useTimelineSelection } from '@/tools/video-editor/hooks/useTimelineSelection';
import {
  useTimelineChromeContextValue,
  useTimelineEditorContextValue,
  useTimelinePlaybackContextValue,
} from '@/tools/video-editor/hooks/useTimelineState.contexts';
import type { UseTimelineStateResult } from '@/tools/video-editor/hooks/useTimelineState.types';
import { useTimelineTrackManagement } from '@/tools/video-editor/hooks/useTimelineTrackManagement';

export type { EditorPreferences } from '@/tools/video-editor/hooks/useEditorPreferences';
export type { RenderStatus } from '@/tools/video-editor/hooks/useRenderState';
export type { SaveStatus } from '@/tools/video-editor/hooks/useTimelineSave';

export function useTimelineState(): UseTimelineStateResult {
  const runtime = useVideoEditorRuntime();
  const queryClient = useQueryClient();
  const playback = useTimelinePlayback();
  const preferences = useEditorPreferences(runtime.timelineId);
  const queries = useTimelineQueries(runtime.provider, runtime.timelineId);
  // Shared gate observed by drag/resize writers and read by save/persistence/poll.
  const interactionStateRef = useRef(createInteractionState());
  const save = useTimelineSave(queries, runtime.provider, interactionStateRef);
  const history = useTimelineHistory({
    dataRef: save.dataRef,
    commitData: save.commitData,
  });
  const derived = useDerivedTimeline(save.data, save.selectedClipId, save.selectedTrackId);
  const render = useRenderState(derived.resolvedConfig, derived.renderMetadata);
  const assetOperations = useAssetOperations(
    runtime.provider,
    runtime.timelineId,
    runtime.userId,
    queryClient,
    save.pendingOpsRef,
  );
  const {
    data,
    dataRef,
    eventBus,
    isConflictExhausted,
    selectedClipId,
    selectedTrackId,
    saveStatus,
    setSelectedClipId,
    setSelectedTrackId,
    applyEdit,
    patchRegistry,
    reloadFromServer,
    retrySaveAfterConflict,
    pendingOpsRef,
    isLoading,
  } = save;
  const {
    resolvedConfig,
    compositionSize,
    trackScaleMap,
  } = derived;
  const {
    renderStatus,
    renderLog,
    renderDirty,
    renderProgress,
    renderResultUrl,
    renderResultFilename,
    setRenderDirty,
    startRender,
  } = render;
  const {
    canUndo,
    canRedo,
    checkpoints,
    undo,
    redo,
    jumpToCheckpoint,
    createManualCheckpoint,
    onBeforeCommit,
  } = history;
  const {
    scale,
    scaleWidth,
    preferences: editorPreferences,
    setScaleWidth,
    setActiveClipTab,
    setAssetPanelState,
  } = preferences;
  const {
    registerAsset,
    uploadAsset,
    uploadFiles,
    invalidateAssetRegistry,
  } = assetOperations;
  const { selectedProjectId } = useProjectSelectionContext();
  const { clearGallerySelection, registerPeerClear } = useGallerySelection();
  const selection = useTimelineSelection({
    data,
    selectedClipId,
    selectedTrackId,
    setSelectedClipId,
    clearGallerySelection,
    registerPeerClear,
  });

  useEffect(() => {
    return eventBus.on('beforeCommit', onBeforeCommit);
  }, [eventBus, onBeforeCommit]);

  useEffect(() => {
    return eventBus.on('pruneSelection', selection.pruneSelection);
  }, [eventBus, selection.pruneSelection]);

  useEffect(() => {
    return eventBus.on('saveSuccess', () => {
      setRenderDirty(true);
    });
  }, [eventBus, setRenderDirty]);

  const dragCoordinator = useDragCoordinator({
    dataRef,
    scale,
    scaleWidth,
    startLeft: TIMELINE_START_LEFT,
    rowHeight: ROW_HEIGHT,
  });

  const assetManagement = useAssetManagement({
    dataRef,
    selectedTrackId,
    selectedProjectId,
    setSelectedClipId: selection.setSelectedClipId,
    setSelectedTrackId,
    applyEdit,
    patchRegistry,
    registerAsset,
    uploadAsset,
    invalidateAssetRegistry,
    resolveAssetUrl: runtime.provider.resolveAssetUrl.bind(runtime.provider),
  });

  const clipResize = useClipResize({
    dataRef,
    applyEdit,
  });

  const clipEditing = useClipEditing({
    dataRef,
    resolvedConfig: selection.resolvedConfig,
    selectedClipId: selection.primaryClipId,
    selectedTrack: selection.selectedTrack,
    currentTime: playback.currentTime,
    setSelectedClipId: selection.setSelectedClipId,
    setSelectedTrackId,
    applyEdit,
  });

  const externalDrop = useExternalDrop({
    dataRef,
    pendingOpsRef,
    scale,
    scaleWidth,
    selectedTrackId,
    applyEdit,
    patchRegistry,
    registerAsset,
    uploadAsset,
    invalidateAssetRegistry,
    resolveAssetUrl: runtime.provider.resolveAssetUrl.bind(runtime.provider),
    coordinator: dragCoordinator.coordinator,
    registerGenerationAsset: assetManagement.registerGenerationAsset,
    uploadImageGeneration: assetManagement.uploadImageGeneration,
    uploadVideoGeneration: assetManagement.uploadVideoGeneration,
    handleAssetDrop: assetManagement.handleAssetDrop,
    handleAddTextAt: clipEditing.handleAddTextAt,
    onSeekToTime: playback.onClickTimeArea,
  });

  const trackManagement = useTimelineTrackManagement({
    dataRef,
    resolvedConfig: selection.resolvedConfig,
    selectedClipId: selection.primaryClipId,
    setSelectedTrackId,
    applyEdit,
  });

  const editor = useTimelineEditorContextValue({
    data,
    selection,
    selectedTrackId,
    compositionSize,
    trackScaleMap,
    scale,
    scaleWidth,
    isLoading,
    dataRef,
    pendingOpsRef,
    interactionStateRef,
    editorPreferences,
    setSelectedTrackId,
    setActiveClipTab,
    setAssetPanelState,
    dragCoordinator,
    playback,
    assetManagement,
    clipResize,
    clipEditing,
    externalDrop,
    trackManagement,
    uploadFiles,
    applyEdit,
    patchRegistry,
    registerAsset,
  });

  const chrome = useTimelineChromeContextValue({
    timelineName: runtime.timelineName ?? null,
    saveStatus,
    isConflictExhausted,
    render: {
      renderStatus,
      renderLog,
      renderDirty,
      renderProgress,
      renderResultUrl,
      renderResultFilename,
    },
    history: {
      undo,
      redo,
      canUndo,
      canRedo,
      checkpoints,
      jumpToCheckpoint,
      createManualCheckpoint,
    },
    setScaleWidth,
    trackManagement: {
      handleAddTrack: trackManagement.handleAddTrack,
      handleClearUnusedTracks: trackManagement.handleClearUnusedTracks,
      unusedTrackCount: trackManagement.unusedTrackCount,
    },
    clipEditing: {
      handleAddText: clipEditing.handleAddText,
      handleAddTextAt: clipEditing.handleAddTextAt,
    },
    reloadFromServer,
    retrySaveAfterConflict,
    startRender,
  });

  const playbackValue = useTimelinePlaybackContextValue({ playback });

  return {
    editor,
    chrome,
    playback: playbackValue,
  };
}

import { createContext, useContext, useMemo } from 'react';
import type {
  TimelineEditorContextValue,
  TimelineEditorDataContextValue,
  TimelineEditorOpsContextValue,
} from '@/tools/video-editor/hooks/useTimelineState.types';

const TimelineEditorDataContext = createContext<TimelineEditorDataContextValue | null>(null);
const TimelineEditorOpsContext = createContext<TimelineEditorOpsContextValue | null>(null);

export function TimelineEditorDataContextProvider({
  value,
  children,
}: {
  value: TimelineEditorDataContextValue;
  children: React.ReactNode;
}) {
  return (
    <TimelineEditorDataContext.Provider value={value}>
      {children}
    </TimelineEditorDataContext.Provider>
  );
}

export function TimelineEditorOpsContextProvider({
  value,
  children,
}: {
  value: TimelineEditorOpsContextValue;
  children: React.ReactNode;
}) {
  return (
    <TimelineEditorOpsContext.Provider value={value}>
      {children}
    </TimelineEditorOpsContext.Provider>
  );
}

export function useTimelineEditorData(): TimelineEditorDataContextValue {
  const context = useContext(TimelineEditorDataContext);
  if (!context) {
    throw new Error('useTimelineEditorData must be used within TimelineEditorDataContextProvider');
  }

  return context;
}

export function useTimelineEditorOps(): TimelineEditorOpsContextValue {
  const context = useContext(TimelineEditorOpsContext);
  if (!context) {
    throw new Error('useTimelineEditorOps must be used within TimelineEditorOpsContextProvider');
  }

  return context;
}

/**
 * @deprecated Prefer `useTimelineEditorData()` and `useTimelineEditorOps()`.
 */
export function useTimelineEditorContext(): TimelineEditorContextValue {
  const data = useTimelineEditorData();
  const ops = useTimelineEditorOps();

  return useMemo(
    () => ({ ...data, ...ops }),
    [data, ops],
  );
}

import { useCallback, useEffect, useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { MediaLightbox } from '@/domains/media-lightbox/MediaLightbox';
import type { GenerationRow } from '@/domains/generation/types';
import type { DataProvider } from '@/tools/video-editor/data/DataProvider';
import { DataProviderWrapper } from '@/tools/video-editor/contexts/DataProviderContext';
import { TimelineChromeContextProvider } from '@/tools/video-editor/contexts/TimelineChromeContext';
import {
  TimelineEditorDataContextProvider,
  TimelineEditorOpsContextProvider,
} from '@/tools/video-editor/contexts/TimelineEditorContext';
import { TimelinePlaybackContextProvider } from '@/tools/video-editor/contexts/TimelinePlaybackContext';
import { useEffects } from '@/tools/video-editor/hooks/useEffects';
import { useEffectRegistry } from '@/tools/video-editor/hooks/useEffectRegistry';
import { useEffectResources } from '@/tools/video-editor/hooks/useEffectResources';
import { useTimelineState } from '@/tools/video-editor/hooks/useTimelineState';
import type {
  TimelineActionResizeStart,
  TimelineClipEdgeResizeEnd,
  TimelineEditorDataContextValue,
  TimelineEditorOpsContextValue,
} from '@/tools/video-editor/hooks/useTimelineState.types';
import { loadGenerationForLightbox } from '@/tools/video-editor/lib/generation-utils';
import { useRenderDiagnostic } from '@/tools/video-editor/hooks/usePerfDiagnostics';
import type { ResolvedAssetRegistryEntry } from '@/tools/video-editor/types';

const log = import.meta.env.DEV ? (...args: Parameters<typeof console.log>) => console.log(...args) : () => {};

function isOpenableAssetType(type: string | undefined, url: string | undefined): boolean {
  if (typeof type === 'string' && (type.startsWith('video/') || type.startsWith('image/'))) {
    return true;
  }

  if (!url) {
    return false;
  }

  return /\.(mp4|mov|webm|m4v|png|jpe?g|webp|gif|avif)(\?.*)?$/i.test(url);
}

export function buildVideoEditorLightboxMedia(
  assetKey: string | null,
  asset: ResolvedAssetRegistryEntry | undefined,
): GenerationRow | null {
  if (!assetKey || !asset) {
    return null;
  }

  const src = asset.src || asset.file;
  if (!src || !isOpenableAssetType(asset.type, src)) {
    return null;
  }

  const isVideo = asset.type?.startsWith('video/')
    || /\.(mp4|mov|webm|m4v)(\?.*)?$/i.test(src);

  return {
    id: assetKey,
    generation_id: asset.generationId || assetKey,
    location: src,
    imageUrl: src,
    thumbUrl: asset.thumbnailUrl || src,
    type: isVideo ? 'video' : 'image',
    primary_variant_id: asset.variantId || null,
    name: asset.file,
  };
}

function InnerProvider({
  children,
  userId,
}: {
  children: React.ReactNode;
  userId: string;
}) {
  useRenderDiagnostic('VideoEditorProvider');
  const effectsQuery = useEffects(userId);
  const effectResources = useEffectResources(userId);
  useEffectRegistry(
    effectsQuery.data?.map((effect) => ({
      slug: effect.slug,
      code: effect.code,
    })),
    effectResources.effects,
  );
  const { editor, chrome, playback } = useTimelineState();
  const [lightboxAssetKey, setLightboxAssetKey] = useState<string | null>(null);
  const lightboxAsset = lightboxAssetKey ? editor.resolvedConfig?.registry[lightboxAssetKey] : undefined;
  const lightboxFallbackMedia = useMemo(
    () => buildVideoEditorLightboxMedia(lightboxAssetKey, lightboxAsset),
    [lightboxAsset, lightboxAssetKey],
  );
  const lightboxGenerationId = lightboxAsset?.generationId ?? null;
  const lightboxQuery = useQuery({
    queryKey: ['video-editor', 'lightbox', lightboxGenerationId],
    queryFn: () => loadGenerationForLightbox(lightboxGenerationId as string),
    enabled: Boolean(lightboxGenerationId),
    staleTime: 60_000,
  });

  useEffect(() => {
    if (
      !lightboxAssetKey
      || !lightboxGenerationId
      || lightboxQuery.isLoading
      || lightboxQuery.data
      || lightboxFallbackMedia
    ) {
      return;
    }

    log('[video-editor] lightbox query returned no data; clearing asset key', {
      assetKey: lightboxAssetKey,
      generationId: lightboxGenerationId,
    });
    setLightboxAssetKey(null);
  }, [lightboxAssetKey, lightboxFallbackMedia, lightboxGenerationId, lightboxQuery.data, lightboxQuery.isLoading]);

  const onDoubleClickAsset = useCallback((assetKey: string) => {
    const asset = editor.resolvedConfig?.registry[assetKey];
    log('[video-editor] onDoubleClickAsset', {
      assetKey,
      hasAsset: Boolean(asset),
      generationId: asset?.generationId ?? null,
      file: asset?.file ?? null,
      type: asset?.type ?? null,
    });
    if (!buildVideoEditorLightboxMedia(assetKey, asset)) {
      return;
    }

    setLightboxAssetKey(assetKey);
  }, [editor.resolvedConfig]);

  useEffect(() => {
    if (!lightboxAssetKey) {
      return;
    }

    log('[video-editor] lightbox state', {
      assetKey: lightboxAssetKey,
      generationId: lightboxGenerationId,
      isLoading: lightboxQuery.isLoading,
      hasData: Boolean(lightboxQuery.data),
      hasFallbackMedia: Boolean(lightboxFallbackMedia),
      mediaId: lightboxQuery.data?.id ?? null,
      mediaType: lightboxQuery.data?.type ?? null,
      mediaLocation: lightboxQuery.data?.location ?? null,
    });
  }, [lightboxAssetKey, lightboxFallbackMedia, lightboxGenerationId, lightboxQuery.data, lightboxQuery.isLoading]);

  const editorData = useMemo<TimelineEditorDataContextValue>(() => ({
    data: editor.data,
    resolvedConfig: editor.resolvedConfig,
    selectedClipId: editor.selectedClipId,
    selectedClipIds: editor.selectedClipIds,
    selectedClipIdsRef: editor.selectedClipIdsRef,
    additiveSelectionRef: editor.additiveSelectionRef,
    selectedTrackId: editor.selectedTrackId,
    primaryClipId: editor.primaryClipId,
    selectedClip: editor.selectedClip,
    selectedTrack: editor.selectedTrack,
    selectedClipHasPredecessor: editor.selectedClipHasPredecessor,
    compositionSize: editor.compositionSize,
    trackScaleMap: editor.trackScaleMap,
    scale: editor.scale,
    scaleWidth: editor.scaleWidth,
    isLoading: editor.isLoading,
    dataRef: editor.dataRef,
    pendingOpsRef: editor.pendingOpsRef,
    interactionStateRef: editor.interactionStateRef,
    coordinator: editor.coordinator,
    indicatorRef: editor.indicatorRef,
    editAreaRef: editor.editAreaRef,
    preferences: editor.preferences,
    timelineRef: editor.timelineRef,
    timelineWrapperRef: editor.timelineWrapperRef,
  }), [editor]);

  const onActionResizeStart: TimelineActionResizeStart = editor.onActionResizeStart;
  const onClipEdgeResizeEnd: TimelineClipEdgeResizeEnd = editor.onClipEdgeResizeEnd;

  const editorOps = useMemo<TimelineEditorOpsContextValue>(() => ({
    setSelectedClipId: editor.setSelectedClipId,
    isClipSelected: editor.isClipSelected,
    selectClip: editor.selectClip,
    selectClips: editor.selectClips,
    replaceTimelineSelection: editor.replaceTimelineSelection,
    addToSelection: editor.addToSelection,
    clearSelection: editor.clearSelection,
    setSelectedTrackId: editor.setSelectedTrackId,
    setActiveClipTab: editor.setActiveClipTab,
    setAssetPanelState: editor.setAssetPanelState,
    registerGenerationAsset: editor.registerGenerationAsset,
    onCursorDrag: editor.onCursorDrag,
    onClickTimeArea: editor.onClickTimeArea,
    onActionResizeStart,
    onClipEdgeResizeEnd,
    onOverlayChange: editor.onOverlayChange,
    onTimelineDragOver: editor.onTimelineDragOver,
    onTimelineDragLeave: editor.onTimelineDragLeave,
    onTimelineDrop: editor.onTimelineDrop,
    handleAssetDrop: editor.handleAssetDrop,
    handleUpdateClips: editor.handleUpdateClips,
    handleUpdateClipsDeep: editor.handleUpdateClipsDeep,
    handleDeleteClips: editor.handleDeleteClips,
