          scaleSplitCount={5}
          startLeft={TIMELINE_START_LEFT}
          rowHeight={ROW_HEIGHT}
          minScaleCount={scaleCount}
          maxScaleCount={scaleCount}
          selectedTrackId={selectedTrackId}
          getActionRender={getActionRender}
          onSelectTrack={setSelectedTrackId}
          onTrackChange={handleTrackPopoverChange}
          onRemoveTrack={handleRemoveTrack}
          onTrackDragEnd={handleTrackDragEnd}
          trackSensors={trackSensors}
          onCursorDrag={onCursorDrag}
          onClickTimeArea={onClickTimeArea}
          onActionResizeStart={resizeStartHandler}
          onClipEdgeResizeEnd={clipEdgeResizeEndHandler}
          shotGroups={shotGroups}
          finalVideoMap={finalVideoMap}
          staleShotGroupIds={staleShotGroupIds}
          activeTaskClipIds={activeTaskClipIds}
          onShotGroupNavigate={handleShotGroupNavigate}
          onShotGroupGenerateVideo={handleShotGroupGenerateVideo}
          onShotGroupUnpin={(group) => {
            unpinGroup(group.shotId, group.trackId);
          }}
          onShotGroupDelete={(group) => {
            handleDeleteClips(group.clipIds, { allowPinnedGroupDelete: true });
            unpinGroup(group.shotId, group.trackId);
          }}
          onShotGroupSwitchToFinalVideo={(group) => {
            const finalVideo = finalVideoMap.get(group.shotId);
            if (finalVideo) {
              dismissFinalVideo(finalVideo.id);
            }
            handleSwitchToFinalVideo(group);
          }}
          onShotGroupSwitchToImages={(group) => {
            handleSwitchToImages(group);
          }}
          onShotGroupUpdateToLatestVideo={handleUpdateToLatestVideo}
          onSelectClips={selectClips}
          dragSessionRef={dragSessionRef}
          interactionStateRef={interactionStateRef}
          marqueeRect={marqueeRect}
          onEditAreaPointerDown={onMarqueePointerDown}
          onAddTrack={chrome.handleAddTrack}
          onAddTextAt={chrome.handleAddTextAt}
          unusedTrackCount={chrome.unusedTrackCount}
          onClearUnusedTracks={chrome.handleClearUnusedTracks}
          newTrackDropLabel={newTrackDropLabel}
        />
        <DropIndicator ref={indicatorRef} editAreaRef={editAreaRef} onNewTrackLabel={setNewTrackDropLabel} />
      </div>

      {videoModalShot && (
        <>
          {/* VideoGenerationModal only uses app-wide providers, so it can open from timeline selection flow. */}
          <VideoGenerationModal
            isOpen={true}
            onClose={() => { setVideoModalShot(null); setVideoModalShowImages(false); }}
            shot={videoModalShot}
            defaultTopOpen={videoModalShowImages}
          />
        </>
      )}
    </div>
  );
}

export const TimelineEditor = memo(TimelineEditorComponent);

import {
  useEffect,
  useRef,
} from 'react';
import type { InteractionStateRef } from '@/tools/video-editor/lib/interaction-state';
import { useTimelineCommit } from '@/tools/video-editor/hooks/useTimelineCommit';
import { TimelineEventBus } from '@/tools/video-editor/hooks/useTimelineEventBus';
import { useTimelinePersistence } from '@/tools/video-editor/hooks/useTimelinePersistence';
import { usePollSync, type UsePollSyncQueries } from '@/tools/video-editor/hooks/usePollSync';
import { useVideoEditorRuntime } from '@/tools/video-editor/contexts/DataProviderContext';
import type { DataProvider } from '@/tools/video-editor/data/DataProvider';
export { shouldAcceptPolledData } from '@/tools/video-editor/lib/timeline-save-utils';
export type { SaveStatus } from '@/tools/video-editor/hooks/useTimelinePersistence';

type UseTimelineSaveQueries = UsePollSyncQueries;

export type { InteractionStateRef } from '@/tools/video-editor/lib/interaction-state';

export function useTimelineSave(
  queries: UseTimelineSaveQueries,
  provider: DataProvider,
  interactionStateRef: InteractionStateRef,
) {
  const { timelineId } = useVideoEditorRuntime();
  const lastSavedSignatureRef = useRef('');
  const savedSeqRef = useRef(0);
  const configVersionRef = useRef(1);
  const eventBusRef = useRef(new TimelineEventBus());
  const commit = useTimelineCommit({
    eventBus: eventBusRef.current,
    lastSavedSignatureRef,
  });
  const persistence = useTimelinePersistence({
    provider,
    timelineId,
    eventBus: eventBusRef.current,
    dataRef: commit.dataRef,
    commitData: commit.commitData,
    selectedClipIdRef: commit.selectedClipIdRef,
    selectedTrackIdRef: commit.selectedTrackIdRef,
    editSeqRef: commit.editSeqRef,
    savedSeqRef,
    configVersionRef,
    lastSavedSignatureRef,
    interactionStateRef,
  });

  useEffect(() => {
    return eventBusRef.current.on('scheduleSave', persistence.scheduleSave);
  }, [persistence.scheduleSave]);

  usePollSync({
    queries,
    provider,
    commitData: commit.commitData,
    dataRef: commit.dataRef,
    selectedClipIdRef: commit.selectedClipIdRef,
    selectedTrackIdRef: commit.selectedTrackIdRef,
    editSeqRef: commit.editSeqRef,
    pendingOpsRef: commit.pendingOpsRef,
    savedSeqRef,
    configVersionRef,
    lastSavedSignatureRef,
    isSavingRef: persistence.isSavingRef,
    interactionStateRef,
  });

  return {
    data: commit.data,
    dataRef: commit.dataRef,
    isConflictExhausted: persistence.isConflictExhausted,
    selectedClipId: commit.selectedClipId,
    selectedTrackId: commit.selectedTrackId,
    saveStatus: persistence.saveStatus,
    setSelectedClipId: commit.setSelectedClipId,
    setSelectedTrackId: commit.setSelectedTrackId,
    applyEdit: commit.applyEdit,
    patchRegistry: commit.patchRegistry,
    commitData: commit.commitData,
    eventBus: eventBusRef.current,
    reloadFromServer: persistence.reloadFromServer,
    retrySaveAfterConflict: persistence.retrySaveAfterConflict,
    editSeqRef: commit.editSeqRef,
    pendingOpsRef: commit.pendingOpsRef,
    savedSeqRef,
    selectedClipIdRef: commit.selectedClipIdRef,
    selectedTrackIdRef: commit.selectedTrackIdRef,
    isLoading: queries.timelineQuery.isLoading && !commit.data,
  };
}

