  updates: ClipEdgeResizeUpdate[],
) => {
  const row = rows.find((candidate) => candidate.id === rowId);
  const action = row?.actions.find((candidate) => candidate.id === clipId);
  const update = getUpdateForClip(updates, clipId);
  if (!row || !action || !update) {
    return null;
  }

  return {
