import { useCallback, useLayoutEffect, useRef, useState } from 'react';

export interface SelectClipOptions {
  toggle?: boolean;
}

export interface UseMultiSelectResult {
  selectedClipIds: ReadonlySet<string>;
  selectedClipIdsRef: React.MutableRefObject<Set<string>>;
  additiveSelectionRef: React.MutableRefObject<boolean>;
  primaryClipId: string | null;
  selectClip: (clipId: string, opts?: SelectClipOptions) => void;
  selectClips: (clipIds: Iterable<string>) => void;
  addToSelection: (clipIds: Iterable<string>) => void;
  clearSelection: () => void;
  isClipSelected: (clipId: string) => boolean;
  pruneSelection: (validIds: Set<string>) => void;
}

const getFirstSetValue = (values: ReadonlySet<string>): string | null => {
  for (const value of values) {
    return value;
  }

  return null;
};

const getPrimaryClipId = (
  selectedClipIds: ReadonlySet<string>,
  preferredPrimaryClipId: string | null,
): string | null => {
  if (preferredPrimaryClipId && selectedClipIds.has(preferredPrimaryClipId)) {
    return preferredPrimaryClipId;
  }

  return getFirstSetValue(selectedClipIds);
};

const areSetsEqual = (left: ReadonlySet<string>, right: ReadonlySet<string>): boolean => {
  if (left.size !== right.size) {
    return false;
  }

  for (const value of left) {
    if (!right.has(value)) {
      return false;
    }
  }

  return true;
};

const buildSelectionSet = (clipIds: Iterable<string>): Set<string> => {
  const nextSelection = new Set<string>();

  for (const clipId of clipIds) {
    nextSelection.add(clipId);
  }

  return nextSelection;
};

export function useMultiSelect(): UseMultiSelectResult {
  const [selectedClipIdsState, setSelectedClipIdsState] = useState<Set<string>>(() => new Set());
  const [primaryClipIdState, setPrimaryClipIdState] = useState<string | null>(null);

  const selectedClipIdsRef = useRef<Set<string>>(selectedClipIdsState);
  const additiveSelectionRef = useRef(false);
  const primaryClipIdRef = useRef<string | null>(primaryClipIdState);

  useLayoutEffect(() => {
    selectedClipIdsRef.current = selectedClipIdsState;
    primaryClipIdRef.current = primaryClipIdState;
  }, [primaryClipIdState, selectedClipIdsState]);

  const commitSelection = useCallback((
    nextSelection: Set<string>,
    nextPrimaryClipId: string | null,
    nextIsAdditiveSelection: boolean,
  ) => {
    selectedClipIdsRef.current = nextSelection;
    additiveSelectionRef.current = nextIsAdditiveSelection;
    primaryClipIdRef.current = nextPrimaryClipId;
    setSelectedClipIdsState(nextSelection);
    setPrimaryClipIdState(nextPrimaryClipId);
  }, []);

  const clearSelection = useCallback(() => {
    if (selectedClipIdsRef.current.size === 0 && primaryClipIdRef.current === null) {
      return;
    }

    commitSelection(new Set(), null, false);
  }, [commitSelection]);

  const selectClip = useCallback((clipId: string, opts?: SelectClipOptions) => {
    if (!opts?.toggle) {
      commitSelection(new Set([clipId]), clipId, false);
      return;
    }

    const nextSelection = new Set(selectedClipIdsRef.current);
    if (nextSelection.has(clipId)) {
      nextSelection.delete(clipId);
      commitSelection(
        nextSelection,
        getPrimaryClipId(
          nextSelection,
          primaryClipIdRef.current === clipId ? null : primaryClipIdRef.current,
        ),
        nextSelection.size > 1,
      );
      return;
    }

    nextSelection.add(clipId);
    commitSelection(nextSelection, clipId, nextSelection.size > 1);
  }, [commitSelection]);

  const selectClips = useCallback((clipIds: Iterable<string>) => {
    const nextSelection = buildSelectionSet(clipIds);
    commitSelection(nextSelection, getPrimaryClipId(nextSelection, null), false);
  }, [commitSelection]);

  const addToSelection = useCallback((clipIds: Iterable<string>) => {
    const nextSelection = new Set(selectedClipIdsRef.current);
    for (const clipId of clipIds) {
      nextSelection.add(clipId);
    }

    const nextPrimaryClipId = getPrimaryClipId(nextSelection, primaryClipIdRef.current);
    if (
      areSetsEqual(selectedClipIdsRef.current, nextSelection)
      && primaryClipIdRef.current === nextPrimaryClipId
    ) {
      return;
    }

    commitSelection(nextSelection, nextPrimaryClipId, nextSelection.size > 1);
  }, [commitSelection]);

  const isClipSelected = useCallback((clipId: string) => {
    return selectedClipIdsRef.current.has(clipId);
  }, []);

  const pruneSelection = useCallback((validIds: Set<string>) => {
    const nextSelection = new Set<string>();
    for (const clipId of selectedClipIdsRef.current) {
      if (validIds.has(clipId)) {
        nextSelection.add(clipId);
      }
    }

    const nextPrimaryClipId = getPrimaryClipId(nextSelection, primaryClipIdRef.current);
    if (
      areSetsEqual(selectedClipIdsRef.current, nextSelection)
      && primaryClipIdRef.current === nextPrimaryClipId
    ) {
      return;
    }

    commitSelection(nextSelection, nextPrimaryClipId, additiveSelectionRef.current && nextSelection.size > 1);
  }, [commitSelection]);

  return {
    selectedClipIds: selectedClipIdsState,
    selectedClipIdsRef,
    additiveSelectionRef,
    primaryClipId: primaryClipIdState,
    selectClip,
    selectClips,
    addToSelection,
    clearSelection,
    isClipSelected,
    pruneSelection,
  };
}

import {
  useCallback,
  useEffect,
  useLayoutEffect,
  type Dispatch,
  type SetStateAction,
} from 'react';
import { useDerivedTimeline } from '@/tools/video-editor/hooks/useDerivedTimeline';
import {
  useMultiSelect,
  type SelectClipOptions,
  type UseMultiSelectResult,
} from '@/tools/video-editor/hooks/useMultiSelect';
import type {
  TimelineResolvedConfig,
  TimelineSelectedClip,
  TimelineSelectedTrack,
  TimelineSetSelectedClipId,
} from '@/tools/video-editor/hooks/timeline-state-types';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';

export interface UseTimelineSelectionArgs {
  data: TimelineData | null;
  selectedClipId: string | null;
  selectedTrackId: string | null;
  setSelectedClipId: TimelineSetSelectedClipId;
  clearGallerySelection: () => void;
  registerPeerClear: (clearPeerSelection: (() => void) | null) => void;
}

export interface UseTimelineSelectionResult {
  selectedClipIds: UseMultiSelectResult['selectedClipIds'];
  selectedClipIdsRef: UseMultiSelectResult['selectedClipIdsRef'];
  additiveSelectionRef: UseMultiSelectResult['additiveSelectionRef'];
  primaryClipId: UseMultiSelectResult['primaryClipId'];
  selectedClip: TimelineSelectedClip;
  selectedTrack: TimelineSelectedTrack;
  selectedClipHasPredecessor: boolean;
  resolvedConfig: TimelineResolvedConfig;
  addToSelection: UseMultiSelectResult['addToSelection'];
  clearSelection: UseMultiSelectResult['clearSelection'];
  replaceTimelineSelection: UseMultiSelectResult['selectClips'];
  isClipSelected: UseMultiSelectResult['isClipSelected'];
  pruneSelection: UseMultiSelectResult['pruneSelection'];
  selectClip: UseMultiSelectResult['selectClip'];
  selectClips: UseMultiSelectResult['selectClips'];
  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
}

const getFirstSelectedClipId = (clipIds: ReadonlySet<string>): string | null => {
  for (const clipId of clipIds) {
    return clipId;
  }

  return null;
};

const getPrimaryClipId = (
  clipIds: ReadonlySet<string>,
  preferredClipId: string | null,
): string | null => {
  if (preferredClipId && clipIds.has(preferredClipId)) {
    return preferredClipId;
  }

  return getFirstSelectedClipId(clipIds);
};

export function useTimelineSelection({
  data,
  selectedClipId,
  selectedTrackId,
  setSelectedClipId: setSelectionState,
  clearGallerySelection,
  registerPeerClear,
}: UseTimelineSelectionArgs): UseTimelineSelectionResult {
  const multiSelect = useMultiSelect();
  const {
    addToSelection: addToSelectionState,
    clearSelection: clearSelectionState,
    isClipSelected,
    primaryClipId,
    pruneSelection,
    selectClip: selectClipState,
    selectClips: selectClipsState,
    selectedClipIds,
    selectedClipIdsRef,
    additiveSelectionRef,
  } = multiSelect;
  const selectionDerived = useDerivedTimeline(data, primaryClipId, selectedTrackId);

  const selectClip = useCallback((clipId: string, opts?: SelectClipOptions) => {
    if (!opts?.toggle) {
      clearGallerySelection();
    }

    let nextPrimaryClipId: string | null = clipId;

    if (opts?.toggle) {
      const nextSelection = new Set(selectedClipIdsRef.current);
      if (nextSelection.has(clipId)) {
        nextSelection.delete(clipId);
        nextPrimaryClipId = getPrimaryClipId(
          nextSelection,
          primaryClipId === clipId ? null : primaryClipId,
        );
      }
    }

    selectClipState(clipId, opts);
    setSelectionState(nextPrimaryClipId);
  }, [clearGallerySelection, primaryClipId, selectClipState, selectedClipIdsRef, setSelectionState]);

  const selectClips = useCallback((clipIds: Iterable<string>) => {
    clearGallerySelection();

    const nextSelection = new Set<string>();
    for (const clipId of clipIds) {
      nextSelection.add(clipId);
    }

    selectClipsState(nextSelection);
    setSelectionState(getPrimaryClipId(nextSelection, null));
  }, [clearGallerySelection, selectClipsState, setSelectionState]);

  const addToSelection = useCallback((clipIds: Iterable<string>) => {
    const nextSelection = new Set(selectedClipIdsRef.current);
    const nextClipIds = new Set<string>();
    for (const clipId of clipIds) {
      nextSelection.add(clipId);
      nextClipIds.add(clipId);
    }

    addToSelectionState(nextClipIds);
    setSelectionState(getPrimaryClipId(nextSelection, primaryClipId));
  }, [addToSelectionState, primaryClipId, selectedClipIdsRef, setSelectionState]);

  const clearSelection = useCallback(() => {
    clearGallerySelection();
    clearSelectionState();
    setSelectionState(null);
  }, [clearGallerySelection, clearSelectionState, setSelectionState]);

  const replaceTimelineSelection = useCallback((clipIds: Iterable<string>) => {
    const nextSelection = new Set<string>();
    for (const clipId of clipIds) {
      nextSelection.add(clipId);
    }

    selectClipsState(nextSelection);
    setSelectionState(getPrimaryClipId(nextSelection, null));
  }, [selectClipsState, setSelectionState]);

  const clearTimelineOnly = useCallback(() => {
    clearSelectionState();
    setSelectionState(null);
  }, [clearSelectionState, setSelectionState]);

  useEffect(() => {
    registerPeerClear(clearTimelineOnly);
    return () => {
      registerPeerClear(null);
    };
  }, [clearTimelineOnly, registerPeerClear]);

  const setSelectedClipId = useCallback<Dispatch<SetStateAction<string | null>>>((updater) => {
    const nextClipId = typeof updater === 'function'
      ? updater(primaryClipId)
      : updater;

    if (nextClipId === null) {
      clearSelection();
      return;
    }

    selectClip(nextClipId);
  }, [clearSelection, primaryClipId, selectClip]);

  useLayoutEffect(() => {
    if (!selectedClipId || selectedClipId === primaryClipId) {
      return;
    }

    clearGallerySelection();
    selectClipState(selectedClipId);
  }, [clearGallerySelection, primaryClipId, selectClipState, selectedClipId]);

  return {
    selectedClipIds,
    selectedClipIdsRef,
    additiveSelectionRef,
    primaryClipId,
    selectedClip: selectionDerived.selectedClip,
    selectedTrack: selectionDerived.selectedTrack,
    selectedClipHasPredecessor: selectionDerived.selectedClipHasPredecessor,
    resolvedConfig: selectionDerived.resolvedConfig,
    addToSelection,
    clearSelection,
    replaceTimelineSelection,
    isClipSelected,
    pruneSelection,
    selectClip,
    selectClips,
    setSelectedClipId,
  };
}

import { useEffect } from 'react';
import { isEditableTarget } from '@/tools/video-editor/lib/coordinate-utils';

interface UseKeyboardShortcutsOptions {
  hasSelectedClip: boolean;
  canMoveSelectedClipToTrack: boolean;
  selectedClipIds: ReadonlySet<string>;
  moveSelectedClipsToTrack: (direction: 'up' | 'down', selectedClipIds: ReadonlySet<string>) => void;
  undo: () => void;
  redo: () => void;
  selectAllClips: () => void;
  togglePlayPause: () => void;
  seekRelative: (deltaSeconds: number) => void;
  toggleMute: () => void;
  splitSelectedClip: () => void;
  deleteSelectedClip: () => void;
  clearSelection: () => void;
}

export function useKeyboardShortcuts({
  hasSelectedClip,
  canMoveSelectedClipToTrack,
  selectedClipIds,
  moveSelectedClipsToTrack,
  undo,
  redo,
  selectAllClips,
  togglePlayPause,
  seekRelative,
  toggleMute,
  splitSelectedClip,
  deleteSelectedClip,
  clearSelection,
}: UseKeyboardShortcutsOptions) {
  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      if (isEditableTarget(event.target)) {
        return;
      }

      const isModifierPressed = event.metaKey || event.ctrlKey;
      const key = event.key.toLowerCase();

      if (isModifierPressed && key === 'z' && !event.shiftKey) {
        event.preventDefault();
        undo();
        return;
      }

      if ((isModifierPressed && key === 'z' && event.shiftKey) || (event.ctrlKey && key === 'y')) {
        event.preventDefault();
        redo();
        return;
      }

      if (event.key === 'ArrowLeft') {
        event.preventDefault();
        seekRelative(-1);
        return;
      }

      if (event.key === 'ArrowRight') {
        event.preventDefault();
        seekRelative(1);
        return;
      }

      if (event.key === 'ArrowUp' && hasSelectedClip) {
        event.preventDefault();
        if (canMoveSelectedClipToTrack) {
          moveSelectedClipsToTrack('up', selectedClipIds);
        }
        return;
      }

      if (event.key === 'ArrowDown' && hasSelectedClip) {
        event.preventDefault();
        if (canMoveSelectedClipToTrack) {
          moveSelectedClipsToTrack('down', selectedClipIds);
        }
        return;
      }

      if (isModifierPressed && key === 'a') {
        event.preventDefault();
        selectAllClips();
        return;
      }

      if (event.code === 'Space') {
        event.preventDefault();
        togglePlayPause();
        return;
      }

      if (key === 'm' && hasSelectedClip) {
        event.preventDefault();
        toggleMute();
        return;
      }

      if (key === 's' && hasSelectedClip) {
        event.preventDefault();
        splitSelectedClip();
        return;
      }

      if ((event.key === 'Backspace' || event.key === 'Delete') && hasSelectedClip) {
        event.preventDefault();
        deleteSelectedClip();
        return;
      }

      if (event.key === 'Escape') {
        event.preventDefault();
        clearSelection();
      }
    };

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [canMoveSelectedClipToTrack, clearSelection, deleteSelectedClip, hasSelectedClip, moveSelectedClipsToTrack, redo, seekRelative, selectAllClips, selectedClipIds, splitSelectedClip, toggleMute, togglePlayPause, undo]);
}

