          actionId={action.id}
          contextMenu={contextMenu}
          menuRef={menuRef}
          closeMenu={closeMenu}
          hasBatchSelection={hasBatchSelection}
          selectedClipIds={selectedClipIds}
          isInPinnedShotGroup={isInPinnedShotGroup}
