      </div>
      <div className="px-2 pt-2 text-[11px] text-muted-foreground">
        {hasClipSelection
          ? `${inspectorButtonLabel} actions are available in the inspector.`
          : 'Open the inspector for move, trim, and timeline actions.'}
      </div>
    </div>
  ) : null;

